#include <stdio.h>
#include <limits.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        int current_min = INT_MAX;
        int count = 0;
        for (int i = 0; i < N; ++i) {
            int speed;
            scanf("%d", &speed);
            if (speed < current_min) {
                ++count;
                current_min = speed;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

